@app.route('/api/images/pending', methods=['GET'])
@token_required
def get_pending_images(user_id, user_role):
    limit = request.args.get('limit', 10, type=int)
    limit = min(limit, 100)  # Max 100 images at once
    
    conn = get_db()
    cursor = conn.cursor()
    
    # Get images that this user hasn't annotated yet
    cursor.execute('''
        SELECT i.id, i.image_hash, i.uploaded_at
        FROM images i
        WHERE i.status = 'pending'
        AND i.id NOT IN (
            SELECT image_id FROM annotations WHERE annotator_id = ?
        )
        ORDER BY i.uploaded_at ASC
        LIMIT ?
    ''', (user_id, limit))
    
    images = [dict(row) for row in cursor.fetchall()]
    conn.close()
    
    return jsonify({'images': images}), 200

