# Submit annotation
@app.route('/api/annotations', methods=['POST'])
@token_required
def submit_annotation(user_id, user_role):
    data = request.get_json()
    
    if not data or not data.get('image_id') or not data.get('label'):
        return jsonify({'error': 'image_id and label required'}), 400
    
    image_id = data['image_id']
    label = data['label']
    confidence = data.get('confidence', 1.0)
    
    # Validate confidence
    if not 0 <= confidence <= 1:
        return jsonify({'error': 'Confidence must be between 0 and 1'}), 400
    
    # Sanitize label
    label = str(label).strip()
    if len(label) == 0 or len(label) > 100:
        return jsonify({'error': 'Label must be between 1 and 100 characters'}), 400
    
    try:
        conn = get_db()
        cursor = conn.cursor()
        
        # Verify image exists
        cursor.execute('SELECT id, status FROM images WHERE id = ?', (image_id,))
        image = cursor.fetchone()
        
        if not image:
            conn.close()
            return jsonify({'error': 'Image not found'}), 404
        
        if image['status'] != 'pending':
            conn.close()
            return jsonify({'error': 'Image already labeled'}), 400
        
        # Insert annotation
        cursor.execute('''
            INSERT INTO annotations (image_id, annotator_id, label, confidence)
            VALUES (?, ?, ?, ?)
        ''', (image_id, user_id, label, confidence))
        
        conn.commit()
        annotation_id = cursor.lastrowid
        
        # Check if we should aggregate labels
        cursor.execute('SELECT COUNT(*) as count FROM annotations WHERE image_id = ?', (image_id,))
        annotation_count = cursor.fetchone()['count']
        
        # Aggregate after 3 annotations (configurable)
        min_annotations = 3
        if annotation_count >= min_annotations:
            aggregate_labels(image_id, cursor, conn)
        
        conn.close()
        
        return jsonify({
            'message': 'Annotation submitted successfully',
            'annotation_id': annotation_id
        }), 201
    except sqlite3.IntegrityError:
        return jsonify({'error': 'You have already annotated this image'}), 409

# Aggregate labels using majority voting
def aggregate_labels(image_id, cursor, conn):
    cursor.execute('''
        SELECT label, confidence FROM annotations WHERE image_id = ?
    ''', (image_id,))
    
    annotations = cursor.fetchall()
    
    if not annotations:
        return
    
    # Weighted majority voting
    label_scores = {}
    for ann in annotations:
        label = ann['label']
        confidence = ann['confidence']
        label_scores[label] = label_scores.get(label, 0) + confidence
    
    # Get label with highest score
    final_label = max(label_scores.items(), key=lambda x: x[1])[0]
    
    # Update image with final label
    cursor.execute('''
        UPDATE images SET status = 'labeled', final_label = ? WHERE id = ?
    ''', (final_label, image_id))
    
    # Add to training data
    cursor.execute('''
        INSERT INTO training_data (image_id, label) VALUES (?, ?)
    ''', (image_id, final_label))
    
    conn.commit()

