# Train model on labeled data
@app.route('/api/train', methods=['POST'])
@token_required
@role_required('admin')
def train_model(user_id, user_role):
    data = request.get_json()
    model_name = data.get('model_name', 'default_model')
    
    conn = get_db()
    cursor = conn.cursor()
    
    # Get training data
    cursor.execute('''
        SELECT i.image_data, t.label
        FROM training_data t
        JOIN images i ON t.image_id = i.id
    ''')
    
    training_data = cursor.fetchall()
    
    if len(training_data) == 0:
        conn.close()
        return jsonify({'error': 'No training data available'}), 400
    
    # Prepare data
    X = []
    y = []
    
    for row in training_data:
        try:
            img = Image.open(io.BytesIO(row['image_data']))
            img = img.resize((64, 64))  # Resize to fixed size
            img_array = np.array(img)
            
            # Flatten image
            if len(img_array.shape) == 3:
                img_array = img_array.flatten()
            else:
                img_array = np.stack([img_array] * 3, axis=-1).flatten()
            
            X.append(img_array)
            y.append(row['label'])
        except Exception:
            continue
    
    if len(X) == 0:
        conn.close()
        return jsonify({'error': 'Failed to process training data'}), 400
    
    X = np.array(X)
    
    # Simple label encoding
    unique_labels = list(set(y))
    label_to_idx = {label: idx for idx, label in enumerate(unique_labels)}
    y_encoded = np.array([label_to_idx[label] for label in y])
    
    # Train simple model (logistic regression)
    from sklearn.linear_model import LogisticRegression
    
    model = LogisticRegression(max_iter=1000, random_state=42)
    model.fit(X, y_encoded)
    
    # Calculate training accuracy
    accuracy = model.score(X, y_encoded)
    
    # Serialize model
    import pickle
    model_data = pickle.dumps({
        'model': model,
        'label_mapping': label_to_idx,
        'reverse_mapping': {v: k for k, v in label_to_idx.items()}
    })
    
    # Save model
    cursor.execute('''
        INSERT INTO models (model_name, model_data, accuracy)
        VALUES (?, ?, ?)
    ''', (model_name, model_data, accuracy))
    
    conn.commit()
    model_id = cursor.lastrowid
    conn.close()
    
    return jsonify({
        'message': 'Model trained successfully',
        'model_id': model_id,
        'accuracy': accuracy,
        'training_samples': len(X),
        'num_classes': len(unique_labels)
    }), 201

